const body = $input.item.json.body || {};
const masterToken = $env.MARY_MASTER_TOKEN || '';
if (!body.master_token || body.master_token !== masterToken) return { json: { _unauthorized: true, status: 401 } };
const scenarios = body.scenarios || ['healthy_mga'];
// Synthetic clients
const leadsRows = [];
for (let i = 0; i < 50; i++) {
  leadsRows.push({ vertical_id: 'insurance', demo_mode: true, first_name: 'Demo' + (i+1), last_name: 'Client', email: 'demo+' + (i+1) + '@example.test', phone: '5555550' + (1000 + i), source: 'demo_seed', lead_status: ['New','Engaged','Suitability','Application','Issued'][i % 5] });
}
return { json: { _authorized: true, scenarios, leads: leadsRows, advisors_count: 10, policies_count: 100, reviews_count: 30 } };
